import { Accordion, AccordionContent, AccordionItem, AccordionTrigger } from '@/components/ui/accordion';
import { CheckCircle2, AlertCircle, Mic, Upload, Volume2 } from 'lucide-react';

interface AnalysisResult {
  transcript: string;
  metrics: { wordCount: number; wpm: number; pace: string };
  fillers: { total: number; breakdown: Array<{ word: string; count: number }> };
  scores: { overall: number; pronunciation: number; pace: number; fillers: number; flow: number };
  feedback: string;
  pronunciationTips: Array<{
    word: string;
    issue: string;
    phonetic?: string;
    correct?: string;
    tip?: string;
    example?: string;
    commonMistake?: string;
    audioUrl?: string;
  }>;
  avgConfidence: number;
}

export default function Page() {
  const [analysis, setAnalysis] = useState<AnalysisResult | null>(null);
  const [loading, setLoading] = useState(false);
  const [playingWord, setPlayingWord] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const audioRef = useRef<HTMLAudioElement>(null);

  const playPronunciation = async (word: string, audioUrl?: string) => {
    if (!audioUrl) return;
    
    try {
      setPlayingWord(word);
      if (audioRef.current) {
        audioRef.current.src = audioUrl;
        await audioRef.current.play();
      }
    } catch (error) {
      console.error('Error playing audio:', error);
      setPlayingWord(null);
    }
  };

  const handleFileSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setLoading(true);
    try {
      const formData = new FormData();
      formData.append('audio', file);
      formData.append('duration', '5');

      const response = await fetch('/api/analyze', {
        method: 'POST',
        body: formData,
      });

      const data = await response.json();
      setAnalysis(data);
    } catch (error) {
      console.error('Error analyzing audio:', error);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-900 via-slate-800 to-slate-900 p-6">
      <div className="max-w-4xl mx-auto space-y-6">
        {/* Header */}
        <div className="text-center mb-8">
          <h1 className="text-4xl font-bold text-white mb-2">Speech Analysis Coach</h1>
          <p className="text-slate-400">Upload your speech for AI-powered coaching and feedback</p>
        </div>

        {!analysis ? (
          <>
            {/* Upload Card */}
            <Card className="border-2 border-dashed border-slate-600 bg-slate-800/50 p-12">
              <div className="text-center space-y-4">
                <Upload className="w-16 h-16 mx-auto text-slate-400" />
                <div>
                  <h2 className="text-xl font-semibold text-white mb-2">Upload Your Speech</h2>
                  <p className="text-slate-400 mb-6">
                    Record or select an audio file for analysis
                  </p>
                </div>

                <input
                  ref={fileInputRef}
                  type="file"
                  accept="audio/*"
                  onChange={handleFileSelect}
                  disabled={loading}
                  className="hidden"
                />

                <Button
                  onClick={() => fileInputRef.current?.click()}
                  disabled={loading}
                  size="lg"
                  className="bg-blue-600 hover:bg-blue-700 text-white"
                >
                  {loading ? 'Analyzing...' : 'Choose Audio File'}
                </Button>
              </div>
            </Card>
          </>
        ) : (
          <>
            {/* Results Header */}
            <div className="space-y-4">
              {/* Overall Score */}
              <Card className="bg-gradient-to-r from-blue-600 to-blue-700 text-white p-6">
                <div className="text-center">
                  <div className="text-5xl font-bold mb-2">{analysis.scores.overall}</div>
                  <p className="text-blue-100">Overall Score</p>
                </div>
              </Card>

              {/* Metrics Grid */}
              <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                {[
                  { label: 'Pronunciation', value: analysis.scores.pronunciation, icon: '🎯' },
                  { label: 'Pace', value: analysis.scores.pace, icon: '⏱️' },
                  { label: 'Fillers', value: analysis.scores.fillers, icon: '✨' },
                  { label: 'Flow', value: analysis.scores.flow, icon: '🌊' },
                ].map((metric) => (
                  <Card key={metric.label} className="bg-slate-800 p-4 text-center">
                    <div className="text-2xl mb-2">{metric.icon}</div>
                    <div className="text-2xl font-bold text-white">{metric.value}</div>
                    <div className="text-sm text-slate-400">{metric.label}</div>
                  </Card>
                ))}
              </div>
            </div>

            {/* Pronunciation Coach */}
            <Card className="border-l-4 border-l-amber-500 bg-slate-800">
              <div className="p-6">
                <h3 className="text-xl font-semibold text-white mb-4 flex items-center gap-2">
                  <div className="w-3 h-3 bg-amber-500 rounded-full"></div>
                  Pronunciation Coach
                </h3>
                <p className="text-slate-400 mb-4">Analyzed from your actual speech · Clarity: {analysis.avgConfidence}%</p>

                {analysis.pronunciationTips.length > 0 && analysis.pronunciationTips[0]?.word !== 'pronunciation' ? (
                  <Alert className="mb-4 bg-green-900/20 border-green-700">
                    <CheckCircle2 className="h-4 w-4 text-green-600" />
                    <div className="text-sm text-green-700">
                      Found {analysis.pronunciationTips.length} words to work on. Click to hear the correct pronunciation!
                    </div>
                  </Alert>
                ) : (
                  <Alert className="mb-4 bg-green-900/20 border-green-700">
                    <CheckCircle2 className="h-4 w-4 text-green-600" />
                    <div className="text-sm text-green-700">
                      No significant clarity issues detected. Your words came through clearly!
                    </div>
                  </Alert>
                )}

                <div className="text-slate-300 mb-4">
                  <p className="font-semibold text-white mb-3">Specific corrections based on what you said:</p>
                </div>

                <Accordion type="single" collapsible className="space-y-2">
                  {analysis.pronunciationTips.map((tip, idx) => (
                    <AccordionItem key={idx} value={`tip-${idx}`} className="border border-slate-700 rounded-lg px-4 data-[state=open]:bg-slate-700/50">
                      <AccordionTrigger className="hover:no-underline py-4">
                        <div className="flex items-center justify-between w-full gap-3">
                          <div className="flex-1 text-left">
                            <span className="font-semibold text-amber-400">{tip.word}</span>
                            <span className="text-sm text-slate-400 ml-3">{tip.issue}</span>
                          </div>
                          {tip.audioUrl && (
                            <button
                              onClick={(e) => {
                                e.stopPropagation();
                                playPronunciation(tip.word, tip.audioUrl);
                              }}
                              className={`p-2 rounded-lg transition-colors ${
                                playingWord === tip.word
                                  ? 'bg-amber-500 text-white'
                                  : 'bg-amber-100 text-amber-700 hover:bg-amber-200'
                              }`}
                              title={`Listen to "${tip.word}" pronunciation`}
                            >
                              <Volume2 className="w-4 h-4" />
                            </button>
                          )}
                        </div>
                      </AccordionTrigger>
                      <AccordionContent className="pt-2 pb-4 space-y-3 text-slate-300">
                        <div>
                          <p className="text-sm font-semibold text-slate-400">Phonetic:</p>
                          <p className="text-slate-300 font-mono">{tip.phonetic}</p>
                        </div>
                        <div>
                          <p className="text-sm font-semibold text-slate-400">Correct Pronunciation:</p>
                          <p className="text-slate-300">{tip.correct}</p>
                        </div>
                        <div>
                          <p className="text-sm font-semibold text-slate-400">Tip:</p>
                          <p className="text-slate-300">{tip.tip}</p>
                        </div>
                        <div>
                          <p className="text-sm font-semibold text-slate-400">Example:</p>
                          <p className="text-slate-300 italic">{tip.example}</p>
                        </div>
                        {tip.commonMistake && (
                          <div className="bg-red-900/20 border border-red-700 rounded p-3">
                            <p className="text-sm font-semibold text-red-400">Common Mistake:</p>
                            <p className="text-red-300 text-sm">{tip.commonMistake}</p>
                          </div>
                        )}
                      </AccordionContent>
                    </AccordionItem>
                  ))}
                </Accordion>
              </div>
            </Card>

            {/* Feedback */}
            <Card className="border-l-4 border-l-blue-500 bg-slate-800">
              <div className="p-6">
                <h3 className="font-semibold text-lg text-white mb-4 flex items-center gap-2">
                  <div className="w-3 h-3 bg-blue-500 rounded-full"></div>
                  AI Coaching Feedback
                </h3>
                <div className="space-y-4 text-slate-300">
                  {analysis.feedback.split('\n\n').map((section, idx) => {
                    const lines = section.split('\n').filter(l => l.trim());
                    const isHeader = lines[0]?.startsWith('**');
                    
                    return (
                      <div key={idx} className={isHeader ? "mt-6" : ""}>
                        {lines.map((line, lineIdx) => {
                          if (line.startsWith('**')) {
                            const headerText = line.replace(/\*\*/g, '');
                            return (
                              <h4 key={lineIdx} className="font-bold text-base text-blue-300 mb-3 uppercase tracking-wide">
                                {headerText}
                              </h4>
                            );
                          }
                          
                          if (line.startsWith('Day')) {
                            return (
                              <div key={lineIdx} className="bg-slate-700/50 rounded p-3 mb-2 border-l-2 border-blue-300">
                                <p className="text-sm text-slate-200 font-medium">{line}</p>
                              </div>
                            );
                          }
                          
                          if (line.startsWith('-') || line.startsWith('•')) {
                            return (
                              <div key={lineIdx} className="ml-4 mb-2">
                                <p className="text-sm text-slate-300">{line}</p>
                              </div>
                            );
                          }
                          
                          return line ? (
                            <p key={lineIdx} className="text-sm text-slate-300 mb-3 leading-relaxed">
                              {line}
                            </p>
                          ) : null;
                        })}
                      </div>
                    );
                  })}
                </div>
              </div>
            </Card>

            {/* Transcript */}
            <Card className="bg-slate-800 p-6">
              <h3 className="font-semibold text-white mb-3">Your Transcript</h3>
              <p className="text-slate-300 leading-relaxed text-sm">{analysis.transcript}</p>
            </Card>

            {/* Action Buttons */}
            <div className="flex gap-4">
              <Button
                onClick={() => setAnalysis(null)}
                className="flex-1 bg-blue-600 hover:bg-blue-700 text-white"
              >
                Analyze Another Recording
              </Button>
            </div>
          </>
        )}
      </div>

      {/* Hidden audio element for pronunciation playback */}
      <audio
        ref={audioRef}
        onEnded={() => setPlayingWord(null)}
        crossOrigin="anonymous"
      />
    </div>
  );
}
